// Recopila resultados de todas las llamadas a Zendesk
const items = $input.all().map(i => i.json).filter(Boolean);
const inputs = $('Solo si _action=close').all().map(i => i.json);

const results = items.map((r, i) => {
  const zdId = inputs[i] && inputs[i].zendesk_id;
  const ticket = r && r.ticket;
  const success = !!(ticket && ticket.status === 'solved');
  const errorMsg = !success ? (r && (r.error || r.description || JSON.stringify(r).slice(0, 200))) : null;
  return {
    zendesk_id: zdId,
    success: success,
    new_status: ticket ? ticket.status : null,
    error: errorMsg,
    url: zdId ? `https://soporteyurest.zendesk.com/agent/tickets/${zdId}` : null
  };
});

const ok = results.filter(r => r.success);
const ko = results.filter(r => !r.success);

return [{ json: {
  _action: 'close',
  executed_at: new Date().toISOString(),
  total: results.length,
  success_count: ok.length,
  failure_count: ko.length,
  success_ids: ok.map(r => r.zendesk_id),
  failures: ko,
  full_results: results
} }];
